```class Solution {
    public int countLargestGroup(int n) {
        int[] count = new int[37];
        int maxCount = 0;
        int res = 0;
        for (int i = 1; i <= n; i++) {
            int sum = 0;
            int num = i;
            while (num > 0) {
                sum += num % 10;
                num /= 10;
            }
            count[sum]++;
            if (count[sum] > maxCount) {
                maxCount = count[sum];
                res = 1;
            } else if (count[sum] == maxCount) {
                res++;
            }
        }
        return res;
    }
}```
